import React from 'react';
import { BrowserRouter, Routes, Route } from 'react-router-dom';
import Login from './pages/Login';
import Cadastro from './pages/Cadastro';
import Dashboard from './pages/Dashboard/Dashboard';
import ProjetoDetalhes from './pages/ProjetoDetalhes/ProjetoDetalhes';
import Perfil from './pages/Perfil/Perfil';
import NovaTarefa from './pages/NovaTarefa/NovaTarefa';
import './App.css';

function App() {
  return (
    <BrowserRouter>
      <Routes>
        <Route path="/" element={<Login />} />
        <Route path="/cadastro" element={<Cadastro />} />
        <Route path="/dashboard" element={<Dashboard />} />
        <Route path="/projeto/:id" element={<ProjetoDetalhes />} />
        <Route path="/perfil" element={<Perfil />} />
        <Route path="/nova-tarefa" element={<NovaTarefa />} />
      </Routes>
    </BrowserRouter>
  );
}

export default App;
